SELECT h.*, ste.site_nm AS site_nm, usr.user_nm AS proc_user_nm, cd_ps.code_label AS before_status_cd_nm FROM pdh_prod_status_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN sy_user usr ON usr.user_id = h.proc_user_id LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PRODUCT_STATUS' AND cd_ps.code_value = h.before_status_cd
ORDER BY h.prod_status_hist_id ASC ORDER BY h.prod_status_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

